1	export interface ItemSpec {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	export interface Customer {
9	  yearsWithMHPCO: number;
10	  previousContracts?: number;
11	}
12	
13	export interface QuoteInput {
14	  customer: Customer;
15	  items: ItemSpec[];
16	}
17	
18	export interface QuoteResult {
19	  premium: number;
20	}
21	
22	const PROCESSING_FEE = 5;
23	const FIRST_INSURANCE_RATE = 0.1;
24	const CURSE_SURCHARGE_RATE = 0.5;
25	const HIGH_ENCHANTMENT_THRESHOLD = 5;
26	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
27	const BLOCK_SIZE = 3;
28	const BLOCK_PRICE = 60;
29	const COMPONENT_TYPES = ["rune", "moonstone"];
30	const LOYALTY_YEARS_THRESHOLD = 2;
31	const LOYALTY_DISCOUNT_RATE = 0.2;
32	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
33	
34	const BASE_PREMIUMS: Record<string, number> = {
35	  sword: 100,
36	  amulet: 60,
37	  staff: 80,
38	  potion: 40,
39	  rune: 25,
40	  moonstone: 25,
41	};
42	
43	function basePremiumFor(item: ItemSpec): number {
44	  return BASE_PREMIUMS[item.type] ?? 0;
45	}
46	
47	function sumBasePremiums(items: ItemSpec[]): number {
48	  return items.reduce((sum, item) => sum + basePremiumFor(item), 0);
49	}
50	
51	function countItemsOfType(items: ItemSpec[], type: string): number {
52	  return items.filter((item) => item.type === type).length;
53	}
54	
55	function blockAdjustmentFor(items: ItemSpec[], componentType: string): number {
56	  const count = countItemsOfType(items, componentType);
57	  if (count !== BLOCK_SIZE) return 0;
58	  return BLOCK_PRICE - BLOCK_SIZE * BASE_PREMIUMS[componentType];
59	}
60	
61	function blockAdjustment(items: ItemSpec[]): number {
62	  return COMPONENT_TYPES.reduce(
63	    (sum, componentType) => sum + blockAdjustmentFor(items, componentType),
64	    0
65	  );
66	}
67	
68	function isHighlyEnchanted(item: ItemSpec): boolean {
69	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
70	}
71	
72	function itemSurchargeFor(item: ItemSpec): number {
73	  let surcharge = 0;
74	  if (item.cursed) surcharge += basePremiumFor(item) * CURSE_SURCHARGE_RATE;
75	  if (isHighlyEnchanted(item)) surcharge += basePremiumFor(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE;
76	  return surcharge;
77	}
78	
79	function sumItemSurcharges(items: ItemSpec[]): number {
80	  return items.reduce((sum, item) => sum + itemSurchargeFor(item), 0);
81	}
82	
83	function qualifiesForLoyaltyDiscount(customer: Customer): boolean {
84	  return customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
85	}
86	
87	function loyaltyDiscountFor(customer: Customer, policyBasePremium: number): number {
88	  if (!qualifiesForLoyaltyDiscount(customer)) return 0;
89	  return policyBasePremium * LOYALTY_DISCOUNT_RATE;
90	}
91	
92	function followUpDiscountFor(customer: Customer, policyBasePremium: number): number {
93	  if ((customer.previousContracts ?? 0) <= 0) return 0;
94	  return policyBasePremium * FOLLOW_UP_DISCOUNT_RATE;
95	}
96	
97	function totalPolicyDiscount(customer: Customer, policyBasePremium: number): number {
98	  return (
99	    loyaltyDiscountFor(customer, policyBasePremium) +
100	    followUpDiscountFor(customer, policyBasePremium)
101	  );
102	}
103	
104	export function quote(input: QuoteInput): QuoteResult {
105	  const items = input.items;
106	  const policyBasePremium = sumBasePremiums(items) + blockAdjustment(items);
107	  const itemSurcharges = sumItemSurcharges(items);
108	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_RATE;
109	  const policyDiscount = totalPolicyDiscount(input.customer, policyBasePremium);
110	  return {
111	    premium: Math.ceil(
112	      policyBasePremium + itemSurcharges + firstInsuranceSurcharge - policyDiscount + PROCESSING_FEE
113	    ),
114	  };
115	}
116	
117	export interface ClaimResult {
118	  payout: number;
119	  remainingCap: number;
120	}
121	
122	export interface DamageEntry {
123	  itemType: string;
124	  amount: number;
125	}
126	
127	export interface ClaimInput {
128	  items: ItemSpec[];
129	  damages: DamageEntry[];
130	  remainingCap?: number;
131	}
132	
133	const INSURANCE_VALUES: Record<string, number> = {
134	  sword: 1000,
135	  amulet: 600,
136	  staff: 800,
137	  potion: 400,
138	  rune: 250,
139	  moonstone: 250,
140	};
141	
142	const DEDUCTIBLE = 100;
143	const CAP_MULTIPLIER = 2;
144	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
145	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
146	const DRAGON_MATERIAL = "dragon";
147	
148	function insuranceValueFor(item: ItemSpec): number {
149	  return INSURANCE_VALUES[item.type] ?? 0;
150	}
151	
152	function sumInsuranceValues(items: ItemSpec[]): number {
153	  return items.reduce((sum, item) => sum + insuranceValueFor(item), 0);
154	}
155	
156	function findMatchingItem(items: ItemSpec[], itemType: string): ItemSpec | undefined {
157	  return items.find((item) => item.type === itemType);
158	}
159	
160	function triggersHighEnchantmentRule(item: ItemSpec | undefined): boolean {
161	  const enchantment = item?.enchantment ?? 0;
162	  return enchantment >= CLAIM_HIGH_ENCHANTMENT_THRESHOLD && item?.material !== DRAGON_MATERIAL;
163	}
164	
165	function reimbursementFor(damage: DamageEntry, item: ItemSpec | undefined): number {
166	  const reimbursableAmount = triggersHighEnchantmentRule(item)
167	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
168	    : damage.amount;
169	  return Math.max(0, reimbursableAmount - DEDUCTIBLE);
170	}
171	
172	function sumReimbursements(damages: DamageEntry[], items: ItemSpec[]): number {
173	  return damages.reduce(
174	    (sum, damage) => sum + reimbursementFor(damage, findMatchingItem(items, damage.itemType)),
175	    0
176	  );
177	}
178	
179	function defaultCapFor(items: ItemSpec[]): number {
180	  return CAP_MULTIPLIER * sumInsuranceValues(items);
181	}
182	
183	export function claim(input: ClaimInput): ClaimResult {
184	  const remainingCap = input.remainingCap ?? defaultCapFor(input.items);
185	  const totalReimbursement = sumReimbursements(input.damages, input.items);
186	  const payout = Math.floor(Math.min(totalReimbursement, remainingCap));
187	  return { payout, remainingCap: remainingCap - payout };
188	}
